messageHandlers.script:
# implement your handler here
try:
	deviceList = payload['formattedDevices']
	system.perspective.sendMessage("navigate", payload={"page":"BulkUploads/components/processing"})
	self.getChild("EmbeddedView").props.params.formattedDevices = len(deviceList)

	results = []
	import time
	counter = 0
	for d in deviceList:

		if d['uploadStatus'] == True:
			try:
				status = device.bulkuploadV2.doUpload(d)
				status['dev_eui'] = d['dev_eui']
				results.append(status)
			except Exception as e:
				status = {"message":"Error uploading device: " + str(e), "messageType":"ERROR", "dev_eui":d['dev_eui']}
				results.append(status)
				system.perspective.print("Error uploading device: " + str(e))

		else:
			s = {'dev_eui':d['dev_eui'], 'status':"Not uploaded: " + d['uploadMessage'], "messageType":"ERROR"}
			results.append(s)
		counter += 1
		system.perspective.sendMessage("updateCount", payload={"processed":counter})

	system.perspective.print(results)
	system.perspective.print("moveing to results")

	self.getChild("EmbeddedView").props.params.formattedDevices = results
	self.custom.currentPage = "BulkUploads/components/results"
except Exception as e:
	system.perspective.print("Error uploading devices: " + str(e))
